// Prepare Media Context - Receives output from table_16 Tool
const falResult = $input.first().json;
const request = $("Call 'Fal Tool'").first().json;

// Get media_url from table_16 Tool response
const mediaUrl = falResult.media_url || '';
if (!mediaUrl) {
    throw new Error('media_url is missing from table_16 Tool response.');
}

// Determine generation mode and media type
const generationMode = falResult.generation_mode || request.gen_mode || '';
const mediaType = falResult.media_type || 
                  (generationMode.includes('video') ? 'video' : 'image');
const prompt = falResult.gen_prompt || request.gen_prompt || '';

// Get user identifier
const platformUserId = falResult.telegram_id || 
                       request.telegram_id || 
                       request.chat_id || 
                       '';

if (!platformUserId) {
    console.warn('No platform_user_id found');
}

// Return formatted data for database save and sending
return [{
    json: {
        platform_user_id: platformUserId,
        last_image_url: mediaType === 'image' ? mediaUrl : '',
        last_video_url: mediaType === 'video' ? mediaUrl : '',
        last_gen_mode: generationMode,
        last_gen_prompt: prompt,
        media_url: mediaUrl,
        media_type: mediaType,
        // Pass through for sending to user
        chat_id: request.chat_id || platformUserId,
        caption: falResult.caption || request.caption || '',
        bot_token: request.bot_token,
        is_owner: request.is_owner,
        tenant_id: request.tenant_id
    }
}];

