(function() {
  const update = $('Parse Telegram Update').first().json;
  const caption = update.caption || '';
  const fileName = update.file_name || 'file';
  const fileMime = update.file_mime || 'application/octet-stream';

  const binaryData = $('Download File').first().binary?.data;
  if (!binaryData) throw new Error('No binary data from table_17 File');

  const base64Data = binaryData.data;
  const mimeType = binaryData.mimeType || fileMime;

  const captionInstruction = caption
    ? 'The user sent this file with the following instruction: "' + caption + '"\n\n'
    : '';

  const prompt = captionInstruction +
    'You have received a file named "' + fileName + '".\n\n' +
    'Your task is to extract and preserve the content faithfully for use in a conversation. ' +
    'CRITICAL RULES:\n' +
    '- NEVER invent, infer, or assume any information not explicitly present in the document.\n' +
    '- NEVER paraphrase in a way that changes the meaning or loses specific details.\n' +
    '- If a number, name, date, account number, amount, or reference appears in the document, reproduce it exactly as written.\n' +
    '- If you cannot read part of the document clearly, say so explicitly rather than guessing.\n\n' +
    'Return a JSON object with these fields:\n' +
    '{\n' +
    '  "file_type": "pdf | docx | txt | image_pdf | receipt | invoice | bank_statement | unknown",\n' +
    '  "is_financial": true or false,\n' +
    '  "financial_details": {\n' +
    '    "transaction_refs": [],\n' +
    '    "amounts": [],\n' +
    '    "account_numbers": [],\n' +
    '    "bank_names": [],\n' +
    '    "dates": [],\n' +
    '    "payer": "",\n' +
    '    "payee": "",\n' +
    '    "status": ""\n' +
    '  },\n' +
    '  "full_text": "THE COMPLETE VERBATIM TEXT of the document if under 2000 words. If over 2000 words, include: (1) all headings and section titles verbatim, (2) all numbers, dates, amounts, names, and reference codes verbatim, (3) a faithful condensed version of each section preserving all critical facts — no invented details",\n' +
    '  "page_count": number or null,\n' +
    '  "document_title": "exact title from table_18 or null",\n' +
    '  "key_entities": ["names", "organisations", "dates", "amounts", "references — all verbatim from table_18"]\n' +
    '}\n\n' +
    'For financial documents (receipts, invoices, bank statements, transfer proofs):\n' +
    '- Extract EVERY number, reference code, account number, amount, date, and name — exactly as written\n' +
    '- Nigerian banks: Access Bank, Zenith Bank, GTBank, First Bank, UBA, Sterling Bank, Ecobank, Fidelity Bank, FCMB, Stanbic IBTC, Union Bank, Keystone Bank, Polaris Bank, Wema Bank, Kuda Bank, Opay, Palmpay, Moniepoint\n' +
    '- Naira amounts (₦), BVN, NIN, NUBAN (10-digit account numbers)\n\n' +
    'Return ONLY the JSON object, no markdown, no preamble.';

  const userContent = [];

  if (mimeType.startsWith('image/')) {
    userContent.push({
      type: 'image_url',
      image_url: { url: 'data:' + mimeType + ';base64,' + base64Data }
    });
  } else {
    // PDF and everything else — send as image_url (Groq's only supported base64 format)
    userContent.push({
      type: 'image_url',
      image_url: { url: 'data:' + mimeType + ';base64,' + base64Data }
    });
  }

  userContent.push({ type: 'text', text: prompt });

  return {
    model: 'meta-llama/llama-4-scout-17b-16e-instruct',
    messages: [{ role: 'user', content: userContent }],
    max_tokens: 4096,
    temperature: 0.1
  };
})()
}}

parameters.jsCode:
const update = $('Parse Telegram Update').first().json;
const fileName = update.file_name || 'file';
const fileMime = update.file_mime || '';
const caption = update.caption || '';

let extractedText = '';
let fileType = 'unknown';

// Determine file type from table_19
if (fileMime.includes('wordprocessing')) fileType = 'docx';
else if (fileMime.includes('spreadsheet') || fileMime.includes('excel')) fileType = 'xlsx';
else if (fileMime === 'text/csv') fileType = 'csv';
else if (fileMime === 'text/plain') fileType = 'txt';

// Try spreadsheet/table data (XLSX, CSV) — preserve ALL rows, not capped
try {
  const rows = $input.first().json;
  if (Array.isArray(rows) && rows.length > 0) {
    const headers = Object.keys(rows[0]).join(' | ');
    const dataRows = rows.map(row =>
      Object.values(row).map(v => String(v ?? '')).join(' | ')
    ).join('\n');
    extractedText = 'File: ' + fileName + '\nType: ' + fileType.toUpperCase() + '\n\n' +
                    'Headers: ' + headers + '\n\n' +
                    'Data (' + rows.length + ' rows):\n' + dataRows;
  }
} catch(e) {}

// Try plain text / DOCX output — full content
if (!extractedText) {
  try {
    const raw = $input.first().json.text || $input.first().json.data || '';
    extractedText = 'File: ' + fileName + '\nType: ' + fileType.toUpperCase() + '\n\n' +
                    'Full content:\n' + raw;
  } catch(e) {}
}

if (!extractedText) {
  extractedText = 'File: ' + fileName + ' — could not extract text content.';
}

// Cap at ~12,000 chars to stay within context limits
// This is roughly 3,000 tokens — leaves room for system prompt + agent response
const MAX_CHARS = 12000;
const truncated = extractedText.length > MAX_CHARS;
const finalText = truncated 
  ? extractedText.slice(0, MAX_CHARS) + '\n\n[Content truncated — document is large]'
  : extractedText;

const captionNote = caption ? '\n\nUser instruction: "' + caption + '"' : '';

return [{ json: {
  // This is what goes to Normalise Input as the full user context
  text: finalText + captionNote,
  message_type: 'file',
  file_type: fileType,
  file_name: fileName,
  is_financial: false,  // will be overridden if PDF path detects it
  file_summary: ''       // no summary — full content passed directly
}}];

const response = $input.item.json;
const update = $('Parse Telegram Update').first().json;

// ── Path A: Pre-processed text (from table_23 File Text — XLSX, CSV, TXT)
// These arrive with { text, file_type, file_name } already structured
const isPreProcessed = response?.text && response?.file_type && !response?.choices;

if (isPreProcessed) {
  const fileName = response.file_name || update.file_name || 'file';
  const caption = update.caption || '';
  const captionNote = caption ? '\n\nUser instruction: "' + caption + '"' : '';

  const MAX_CHARS = 15000;
  const raw = response.text || '';
  const truncated = raw.length > MAX_CHARS;
  const finalText = truncated
    ? raw.slice(0, MAX_CHARS) + '\n\n[Document truncated — this is a large file. Only the first portion is shown. If you need specific information not visible here, ask the user to describe it.]'
    : raw;

  return [{
    json: {
      text: finalText + captionNote,
      message_type: 'file',
      file_type: response.file_type || 'unknown',
      is_financial: false,
      file_summary: raw.slice(0, 500) || ''
    }
  }];
}

// ── Path B: Groq API response (from table_24 Processing Agent — PDF, DOCX, images)
const rawOutput = response?.choices?.[0]?.message?.content || '';

let parsed;
try {
  parsed = JSON.parse(rawOutput);
} catch {
  const match = rawOutput.match(/\{[\s\S]*\}/);
  try {
    parsed = match ? JSON.parse(match[0]) : null;
  } catch {
    parsed = null;
  }
}

// If JSON parsing fails entirely, preserve whatever Groq returned as plain text
if (!parsed) {
  parsed = {
    file_type: 'unknown',
    is_financial: false,
    full_text: rawOutput || 'Could not read file content.',
    financial_details: {},
    key_entities: [],
    document_title: null
  };
}

const fileName = update.file_name || 'file';
const caption = update.caption || '';
const captionNote = caption ? '\n\nUser instruction: "' + caption + '"' : '';

let contextText = '';

if (parsed.is_financial) {
  // Financial documents — all structured details surfaced first, then full text
  const fd = parsed.financial_details || {};
  const financialBlock = [
    fd.transaction_refs?.length ? 'Transaction references: ' + fd.transaction_refs.join(', ') : '',
    fd.amounts?.length          ? 'Amounts: '               + fd.amounts.join(', ')           : '',
    fd.account_numbers?.length  ? 'Account numbers: '       + fd.account_numbers.join(', ')   : '',
    fd.bank_names?.length       ? 'Banks: '                 + fd.bank_names.join(', ')         : '',
    fd.dates?.length            ? 'Dates: '                 + fd.dates.join(', ')              : '',
    fd.payer  ? 'Payer: '  + fd.payer  : '',
    fd.payee  ? 'Payee: '  + fd.payee  : '',
    fd.status ? 'Status: ' + fd.status : ''
  ].filter(Boolean).join('\n');

  contextText =
    'File: ' + fileName + '\n' +
    'Type: ' + (parsed.file_type || 'financial document').toUpperCase() + '\n' +
    (parsed.document_title ? 'Title: ' + parsed.document_title + '\n' : '') +
    '\n=== FINANCIAL DETAILS ===\n' +
    financialBlock +
    '\n\n=== FULL DOCUMENT CONTENT ===\n' +
    (parsed.full_text || '') +
    (parsed.key_entities?.length ? '\n\nKey entities: ' + parsed.key_entities.join(', ') : '');

} else {
  // Non-financial documents
  contextText =
    'File: ' + fileName + '\n' +
    'Type: ' + (parsed.file_type || 'document').toUpperCase() + '\n' +
    (parsed.document_title ? 'Title: ' + parsed.document_title + '\n' : '') +
    '\n=== DOCUMENT CONTENT ===\n' +
    (parsed.full_text || '') +
    (parsed.key_entities?.length ? '\n\nKey entities: ' + parsed.key_entities.join(', ') : '');
}

// Cap at 15,000 chars (~3,750 tokens) — leaves room for system prompt + agent response
const MAX_CHARS = 15000;
const truncated = contextText.length > MAX_CHARS;
const finalText = truncated
  ? contextText.slice(0, MAX_CHARS) + '\n\n[Document truncated — this is a large file. Only the first portion is shown. If you need specific information not visible here, ask the user to describe it.]'
  : contextText;

return [{
  json: {
    text: finalText + captionNote,
    message_type: 'file',
    file_type: parsed.file_type || 'unknown',
    is_financial: parsed.is_financial || false,
    file_summary: (parsed.full_text || '').slice(0, 500)  // short preview for logging only
  }
}];

const handleData = $('Handle Output').first().json;
const responseType = handleData.response_type || 'image';

return { json: {
  agent_reply:     handleData.agent_reply || '',
  response_type:   responseType,
  bot_token:       handleData.bot_token,
  chat_id:         handleData.chat_id,
  conversation_id: handleData.conversation_id,
  tenant_id:       handleData.tenant_id,
  user_message:    handleData.user_message || '',
  is_owner:        handleData.is_owner || false
}};

