let text              = update.text || '';
let message_type      = update.message_type;
let image_description = null;
let is_financial      = false;
let source_image_url  = null;   // ← NEW

// ── Audio path ──
try {
  const audioText = $('Format Audio to Text').first().json.message?.text;
  if (audioText) {
    text         = audioText;
    message_type = 'audio';
  }
} catch(e) {}

// ── Store deep-link: /start order_... or /start quote_... ──
const startAction  = update.start_action  || '';
const startProduct = update.start_product || '';
if (startAction === 'order' && startProduct) {
  text         = `I want to order ${startProduct}`;
  message_type = 'text';
} else if (startAction === 'quote' && startProduct) {
  text         = `I'd like a quote for ${startProduct}`;
  message_type = 'text';
}

// ── Image path ──
try {
  const vision = $('Format Vision Output').first().json;
  if (vision && vision.text) {
    text              = vision.text;
    message_type      = 'image';
    image_description = vision.image_description || null;
    is_financial      = vision.is_financial || false;
  }
  // Grab the URL we built in Prepare Vision Request (Case 1: same-message)
  const prepVision = $('Prepare Vision Request').first().json;
  if (prepVision._image_url) {
    source_image_url = prepVision._image_url;
  }
} catch(e) {}

// ── File path ──
try {
  const fileOut = $('Format File Output').first().json;
  if (fileOut && fileOut.text) {
    text         = fileOut.text;
    message_type = 'file';
  }
} catch(e) {}

// ── Fallback to caption ──
if (!text && update.caption) text = update.caption;

return { json: {
  bot_token:        ownerID.bot_token || '',
  tenant_id:        update.tenant_id,
  business_id:      ownerID.business_id,
  chat_id:          update.chat_id,
  sender_id:        update.sender_id,
  first_name:       update.first_name,
  text,
  caption:          update.caption,
  message_type,
  image_description,
  is_financial,
  is_start:         update.is_start,
  voice_file_id:    update.voice_file_id,
  photo_file_id:    update.photo_file_id,
  source_image_url,   // ← NEW: URL if current message had an image, else null
  platform:         'telegram'
}};

const transcriptionText = $json.text || '';

return {
  json: {
    message: {
      text: transcriptionText
    }
  }
};

const items = $input.all();

return items.map(item => {
  const binaryData = item.binary;
  const binaryKey = Object.keys(binaryData || {})[0]; // Get whatever key exists

  if (binaryData && binaryKey) {
    const newBinaryData = { ...binaryData[binaryKey] };
    newBinaryData.fileName = (newBinaryData.fileName || 'audio.ogg').replace('.oga', '.ogg');
    newBinaryData.fileExtension = 'ogg';
    newBinaryData.mimeType = 'audio/ogg';

    return {
      json: item.json,
