});

const data = $input.first().json;

// INPUT credit charges (include LLM cost)
const inputCreditMap = {
  text:    15,
  audio:   27,   // voice note input
  image:   18,   // image input
  file:    18,   // file/PDF input
  video:    0,   // video input blocked at the source
  unknown: 15,   // fallback
};

const msgType = data.message_type_in || 'text';
const inputCredits = inputCreditMap[msgType] ?? 15;

return { json: {
  conversation_id: data.conversation_id,
  tenant_id:       data.tenant_id,
  chat_id:         data.chat_id,
  bot_token:       data.bot_token,
  user_message:    data.user_message,
