  response_type:   data.response_type,
  message_type_in: msgType,
  is_owner:        data.is_owner || false,
  tokens_used:     0,
  credits_charged: inputCredits
}};

const body       = $json.body || {};
const message    = body.message || {};
const chat       = message.chat || {};
const from       = message.from || {};

const tenant_id   = $json.query?.tenantId  || $json.params?.tenantId  || '';
const business_id = $json.query?.businessId || $json.params?.businessId || '';
const text        = (message.text || '').trim();
const message_id  = message.message_id || 0;
const is_start       = text.startsWith('/start');
const start_raw      = text.startsWith('/start ') ? text.slice(7).trim() : '';
const start_payload  = start_raw;
const start_action   = start_raw.startsWith('order_') ? 'order'
                     : start_raw.startsWith('quote_') ? 'quote'
                     : '';
const start_product  = start_action
  ? decodeURIComponent(start_raw.replace(/^(order|quote)_/, '').replace(/_/g, ' '))
  : '';
const first_name  = from.first_name || '';
const username    = from.username   || '';
const caption     = (message.caption || '').trim();

// ── Callback query (inline button taps) ──
const callback_query     = body.callback_query || null;
const callback_query_id  = callback_query ? callback_query.id   : null;
const callback_data      = callback_query ? callback_query.data : null;
const callback_from      = callback_query ? callback_query.from : null;
const callback_sender_id = callback_query ? String(callback_from.id) : null;
const callback_chat_id   = callback_query ? String(callback_query.message?.chat?.id || '') : null;
const is_callback        = !!callback_query;

// ── chat_id and sender_id — handle both message and callback paths ──
const chat_id   = is_callback ? (callback_chat_id || String(chat.id || '')) : String(chat.id || '');
const sender_id = is_callback ? (callback_sender_id || String(from.id || '')) : String(from.id || '');

// ── Audio / Voice ──
const voice          = message.voice || null;
const voice_file_id  = voice ? voice.file_id  : null;
const voice_duration = voice ? voice.duration : null;
const voice_mime     = voice ? voice.mime_type : null;

// ── Photos — all resolutions ──
const photo         = message.photo || null;
let photo_sizes     = null;
let photo_file_id   = null;
let photo_file_id_small  = null;
let photo_file_id_medium = null;
let photo_file_id_large  = null;

if (photo && photo.length > 0) {
  photo_sizes = photo.map(p => ({
    file_id:   p.file_id,
    width:     p.width,
    height:    p.height,
    file_size: p.file_size || null
  }));
  photo_file_id_small  = photo[0]?.file_id || null;
  photo_file_id_medium = photo[1]?.file_id || null;
  photo_file_id_large  = photo[2]?.file_id || photo[1]?.file_id || null;
  photo_file_id        = photo[photo.length - 1]?.file_id || null;
}

// ── Documents / Files ──
const document       = message.document || null;
const file_id        = document ? document.file_id        : null;
const file_name      = document ? document.file_name      : null;
const file_mime      = document ? document.mime_type      : null;
const file_size      = document ? document.file_size      : null;
const file_unique_id = document ? document.file_unique_id : null;

// ── Stickers ──
const sticker         = message.sticker || null;
const sticker_file_id = sticker ? sticker.file_id : null;
const sticker_emoji   = sticker ? sticker.emoji   : null;

// ── Video note ──
const video_note         = message.video_note || null;
const video_note_file_id = video_note ? video_note.file_id : null;

// ── Regular video ──
const video          = message.video || null;
const video_file_id  = video ? video.file_id  : null;
const video_duration = video ? video.duration : null;
const video_mime     = video ? video.mime_type : null;

// ── Message type ──
const message_type =
  voice      ? 'audio'        :
  video_note ? 'video_note'   :
  video      ? 'video'        :
  photo      ? 'image'        :
  document   ? 'file'         :
  sticker    ? 'sticker'      :
  text       ? 'text'         :
  caption    ? 'caption_only' :
  'unknown';

if (!tenant_id)   throw new Error('No tenant_id in webhook URL');
if (!business_id) throw new Error('No business_id in webhook URL');
if (!chat_id)     throw new Error('No chat_id in Telegram update');

return { json: {
  tenant_id,
  business_id,
  chat_id,
  sender_id,
  first_name,
  username,
  text,
  caption,
  message_id,
  is_start,
  start_payload,
  start_action,
  start_product,
  message_type,
  platform: 'telegram',

  voice_file_id,
  voice_duration,
  voice_mime,

  photo_sizes,
  photo_file_id,
  photo_file_id_small,
  photo_file_id_medium,
  photo_file_id_large,

  file_id,
  file_name,
  file_mime,
  file_size,
  file_unique_id,

  video_file_id,
  video_duration,
  video_mime,

  video_note_file_id,

  is_callback,
  callback_query_id,
  callback_data,
  callback_sender_id,
  callback_chat_id,

  sticker_file_id,
  sticker_emoji
}};

