const groqResponse = $input.first().json;
const normalised = $('Normalise Input').first().json;
const conversation = $('Upsert Conversation').first().json;
const telegramParsed = $('Parse Telegram Update').first().json;

const VALID_INTENTS = ['order', 'business', 'reminder', 'personal', 'google', 'speedy'];
let intents = ['order'];

try {
  const raw = groqResponse?.choices?.[0]?.message?.content || '{}';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed_json = JSON.parse(cleaned);
  if (Array.isArray(parsed_json.intents) && parsed_json.intents.length > 0) {
    const filtered = parsed_json.intents
      .map(i => String(i).toLowerCase().trim())
      .filter(i => VALID_INTENTS.includes(i));
    if (filtered.length > 0) intents = filtered;
  }
} catch (e) {}

return {
  json: {
    intents,
    intents_csv: intents.join(','),   // e.g. "order,reminder" or "order"
    tenant_id:        normalised.tenant_id,
    business_id:      normalised.business_id,
    chat_id:          normalised.chat_id,
    sender_id:        normalised.sender_id,
    conversation_id:  conversation.conversation_id,
    text:             normalised.text || '',
    caption:          normalised.caption || '',
    message_type:     normalised.message_type || 'text',
    display_name:     telegramParsed.first_name || 'there',
    username:         telegramParsed.username || '',
    image_id:         normalised.source_image_url || '',
    source:           'telegram',
    is_owner:         true,
    bot_token:        normalised.bot_token || ''
  }
};

const filePath = $('Get Image').first().json.result.file_path;
const botToken  = $('Fetch Owner ID').first().json.bot_token;
const imageUrl  = `[URL]
const caption   = $('Parse Telegram Update').first().json.caption || '';

// Determine if the sender is the business owner
const ownerId  = String($('Fetch Owner ID').first().json.telegram_id || '');
const senderId = String($('Parse Telegram Update').first().json.sender_id || '');
const isOwner  = ownerId && senderId && ownerId === senderId;

const captionNote = caption ? `The sender wrote: "${caption}". ` : '';

// One prompt — returns all fields. Owner agents use product fields.
// Customer agents use description + specs fields. Both get financial detection.
const promptText = `Analyze this image carefully. ${captionNote}
Return ONLY a valid JSON object with exactly these fields:

{
  "is_financial": boolean,
  "financial_type": "account_details" | "receipt" | "transfer_screenshot" | "balance_screenshot" | "none",
  "accounts": [{"account_number": "string", "bank_name": "string", "account_holder_name": "string or null"}],
  "amount_transferred": "naira string or null",
  "image_description": "one clear sentence describing what is in the image",
  "suggested_name": "if this is a product/item, what a seller would call it (e.g. 'Brown Suede Platform Sandals', '3-Tier Fondant Wedding Cake', 'iPhone 15 Pro Max Case Black'). null if not a product.",
  "suggested_category": "single lowercase word for the product category (e.g. 'shoes', 'cakes', 'dresses', 'bags', 'phones', 'jewelry', 'food'). null if not a product.",
  "image_type_hint": "logo" | "product" | "portfolio" | "other",
  "is_product_reference": boolean,
  "product_specs": {"colour": "string or null", "style": "string or null", "material": "string or null", "occasion": "string or null"}
}

RULES:
is_financial = true ONLY for bank account numbers, receipts, transfer screenshots, balance screenshots.
Nigerian banks: Access Bank, Zenith Bank, GTBank, First Bank, UBA, Sterling Bank, Ecobank, Fidelity Bank, FCMB, Stanbic IBTC, Union Bank, Keystone Bank, Polaris Bank, Wema Bank, Kuda Bank, Opay, Palmpay, Moniepoint.

image_type_hint:
  "logo" = a brand mark, logo, or icon (not a product photo)
  "product" = a physical item being sold (clothing, food, shoes, accessories, electronics, etc.)
  "portfolio" = before/after, work sample, service result (hairstyle, cake finished, tailoring)
  "other" = person, document, screenshot, meme, or anything else

suggested_name: Give a specific descriptive name as a seller would write it on a price list.
  Examples: "Red Ankara Wrap Dress", "Brown Suede Platform Sandals Size 40", "4-Tier Fondant Wedding Cake Ivory Gold", "iPhone 15 Pro Max Clear Case"
  NOT: "A shoe", "Dress", "Cake"
  If image_type_hint is "logo" or "other", set suggested_name to null.

is_product_reference = true if this image appears to be a photo of a product someone might want to order (even if it's not the business's own product — e.g. a customer sending a reference photo).

product_specs: extract only what is clearly visible. Set fields to null if not visible.

Return ONLY the JSON. No markdown, no explanation, no preamble.`;

return {
  json: {
    model: 'meta-llama/llama-4-scout-17b-16e-instruct',
    messages: [
      {
        role: 'user',
        content: [
          { type: 'text', text: promptText },
          { type: 'image_url', image_url: { url: imageUrl } }
        ]
      }
    ],
    temperature: 0.1,
    max_tokens: 1024,
    _image_url: imageUrl,
    _is_owner: isOwner
  }
};

const groqResponse = $input.first().json;
const content = groqResponse.choices?.[0]?.message?.content;

if (!content) {
  throw new Error('No content in Groq vision response: ' + JSON.stringify(groqResponse));
}

// Parse JSON — handle markdown fences and extraction fallback
let extractedData;
try {
  extractedData = JSON.parse(content);
} catch {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    try { extractedData = JSON.parse(match[0]); }
    catch { throw new Error('Could not parse vision response: ' + content); }
  } else {
    throw new Error('Could not parse vision response: ' + content);
  }
}

const accounts = extractedData.accounts || [];
accounts.forEach(account => {
  if (account.account_number) {
    const cleaned = String(account.account_number).replace(/\D/g, '');
    account.account_number_cleaned = cleaned;
    account.is_valid = cleaned.length === 10;
  }
});

const isFinancial       = extractedData.is_financial === true;
const isProductRef      = extractedData.is_product_reference === true;
const imageTypeHint     = extractedData.image_type_hint || 'other';
const suggestedName     = extractedData.suggested_name || null;
const suggestedCategory = extractedData.suggested_category || null;
const productSpecs      = extractedData.product_specs || {};
const imageDescription  = extractedData.image_description || '';
const caption           = $('Parse Telegram Update').first().json.caption || '';
const isOwner           = $('Prepare Vision Request').first().json._is_owner || false;

// Build the text that gets injected into table_28 agent's context
let contextText;

if (isFinancial) {
  contextText = accounts.length > 0
    ? `User sent a financial image. Extracted accounts: ${JSON.stringify(accounts)}. Type: ${extractedData.financial_type}. Context: ${extractedData.suggested_response_context || ''}`
    : `User sent a financial image (${extractedData.financial_type}) but no accounts extracted. Description: ${imageDescription}`;
} else if (isOwner && imageTypeHint === 'logo') {
  contextText = `User sent an image that looks like a logo or brand mark. Description: ${imageDescription}.${caption ? ' Caption: ' + caption : ''} [image_type_hint: logo]`;
} else if (isOwner && imageTypeHint === 'product') {
  const specsStr = Object.entries(productSpecs)
    .filter(([,v]) => v)
    .map(([k,v]) => `${k}: ${v}`)
    .join(', ');
  contextText = `User uploaded a product photo. Description: ${imageDescription}.`
    + (suggestedName ? ` Suggested name: ${suggestedName}.` : '')
    + (suggestedCategory ? ` Suggested category: ${suggestedCategory}.` : '')
    + (specsStr ? ` Specs: ${specsStr}.` : '')
    + (caption ? ` Caption: ${caption}.` : '')
    + ` [image_type_hint: product]`;
} else if (!isOwner && isProductRef) {
  const specsStr = Object.entries(productSpecs)
    .filter(([,v]) => v)
    .map(([k,v]) => `${k}: ${v}`)
    .join(', ');
  contextText = `Customer sent a product reference image. Description: ${imageDescription}.`
    + (specsStr ? ` Visible specs: ${specsStr}.` : '')
    + (caption ? ` They wrote: ${caption}.` : '')
    + ` [is_product_reference: true]`;
} else {
  contextText = `User sent an image. Description: ${imageDescription}.${caption ? ' Caption: ' + caption : ''}`;
}

return [{
  json: {
    // existing fields (unchanged — downstream nodes depend on these)
    is_financial:              isFinancial,
    financial_type:            extractedData.financial_type || 'none',
    extractedamount:           extractedData.amount_transferred || null,
    accounts,
    count:                     accounts.length,
    text:                      contextText,
    image_description:         imageDescription,
    suggested_response_context: extractedData.suggested_response_context || '',
    caption,
    // new fields (used by Agent B vision naming + Customer Agent 1)
    image_type_hint:    imageTypeHint,
    suggested_name:     suggestedName,
    suggested_category: suggestedCategory,
    is_product_reference: isProductRef,
    product_specs:      productSpecs,
    is_owner:           isOwner
  }
}];

